import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import ProductsPage from './pages/ProductsPage';
import AdminPage from './pages/AdminPage';
import HomePage from './pages/HomePage';

const ProtectedRoute = ({ children, allowedRole }) => {
  const { isAuthenticated, user, isAdmin, isSeller } = useAuth();

  if (!isAuthenticated) {
    return <Navigate to="/login" />;
  }

  if (allowedRole === 'admin' && !isAdmin) {
    return <Navigate to="/" />;
  }

  if (allowedRole === 'seller' && !isSeller) {
    return <Navigate to="/" />;
  }

  return children;
};

function AppContent() {
  const { isAuthenticated } = useAuth();

  return (
    <div style={styles.app}>
      <nav style={styles.nav}>
        <div style={styles.navContainer}>
          <h2>🛍️ Магазин (пр.7-12)</h2>
          <div>
            <a href="/" style={styles.link}>Главная</a>
            <a href="/products" style={styles.link}>Товары</a>
            {isAuthenticated && (
              <a href="/admin" style={styles.link}>Админка</a>
            )}
          </div>
        </div>
      </nav>

      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/login" element={<LoginPage />} />
        <Route path="/register" element={<RegisterPage />} />
        <Route path="/products" element={
          <ProtectedRoute>
            <ProductsPage />
          </ProtectedRoute>
        } />
        <Route path="/admin" element={
          <ProtectedRoute allowedRole="admin">
            <AdminPage />
          </ProtectedRoute>
        } />
      </Routes>
    </div>
  );
}

const styles = {
  app: { minHeight: '100vh', background: '#0b0f19', color: 'white' },
  nav: { background: '#1a1f2e', padding: '10px 0', borderBottom: '1px solid #333' },
  navContainer: { maxWidth: '1200px', margin: '0 auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  link: { color: 'white', textDecoration: 'none', marginLeft: '20px' }
};

function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <AppContent />
      </AuthProvider>
    </BrowserRouter>
  );
}

export default App;
